SELECT COUNT(1)
FROM sys_permission
WHERE permission_code = #{permissionCode}
  AND deleted = 0

      AND id != #{excludeId}

SELECT FROM sys_permission WHERE deleted = 0
AND (permission_code LIKE CONCAT('%', #{keyword}, '%') OR permission_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sort ASC, id ASC LIMIT #{size} OFFSET #{offset}
